var maxArea = function(height) {
    let l = 0, r = height.length - 1, best = 0;
    while (l < r) {
        const area = Math.min(height[l], height[r]) * (r - l);
        if (area > best) best = area;
        if (height[l] < height[r]) l++; else r--;
    }
    return best;
};
